SELECT 
    h.*, d.`departmentName` AS officeName, d1.`departmentName` AS profitDepName, bd.`basicDataName` AS stateName,
    bd1.`basicDataName` as callbackStateName, bd2.basicDataName as typeName, 
    CONCAT(h.createBy, "-", ui.`realName`) AS createName 
    <if test=" prepend="," searchTimeType compareValue="zrApproverTime"> zrApproverTime 
     spp.customInfo AS extInfo 
FROM
    pm_subcontract_project_header h 



    LEFT JOIN fnd_department d 
        ON h.`officeCode` = d.`departmentNum` 
    LEFT JOIN fnd_department d1 
        ON h.`profitDepCode` = d1.`departmentNum` 
    LEFT JOIN `fnd_basic_data` bd 
        ON h.`state` = bd.`basicDataId` 
        AND bd.`dataTypeCode` = 'subcontractState' 
    LEFT JOIN `fnd_basic_data` bd1 
        ON h.`callbackState` = bd1.`basicDataId` 
        AND bd1.`dataTypeCode` = 'subcontractCbState' 
    LEFT JOIN `fnd_basic_data` bd2 
        ON h.`type` = bd2.`basicDataId` 
        AND bd2.`dataTypeCode` = 'subcontractType' 
    LEFT JOIN fnd_user_info ui 
        ON ui.`username` = h.`createBy`
    <if test=" searchTimeType compareValue="zrApproverTime">
        LEFT JOIN 
            (SELECT 
                ach.`objId` AS subcontractId, MAX(ht.`END_TIME_`) AS zrApproverTime 
            FROM
                `fnd_act_hi_comment` ach 
                LEFT JOIN `act_hi_taskinst` ht 
                    ON ht.ID_ = ach.taskId 
                    AND ht.PROC_INST_ID_ = ach.instId 
            WHERE ach.`result` = 1 
                AND ach.`procdefKey` = 'Subcontract' 
                AND ht.`TASK_DEF_KEY_` = 'approveZRTask' 
            GROUP BY ach.`procdefKey`, ach.`objId`) zra 
            ON zra.subcontractId = h.`id`

    <if test=" searchTimeType compareValue="paymentTime">
        LEFT JOIN `pm_subcontract_project_payment` p 
            ON h.id = p.`subcontractId` 

WHERE h.`effectiveTo` IS NULL 
    <if test=" prepend="AND" id> h.id = #{id} 
    <if test=" prepend="AND" subcontractName> h.subcontractName like concat("%", #{subcontractName}, "%") 
    <if test=" prepend="AND" contractNos> (h.contractNos like concat("%", #{contractNos}, "%") or h.subcontractNo like concat("%", #{contractNos}, "%")) 
    <if test=" prepend="AND" projectIds> h.projectIds like concat("%", #{projectIds}, "%")  
    <if test=" prepend="AND" type> h.type = #{type} 
    <if test=" prepend="AND" state> h.state = #{state} 
    <if test=" prepend="AND" callbackState> callbackState = #{callbackState}  
    <if test=" prepend="AND" facilitatorId> h.facilitatorId = #{facilitatorId} 
    <if test=" prepend="AND" facilitatorName> h.facilitatorName like concat("%", #{facilitatorName}, "%") 
    <if test=" prepend="AND" bankInfo> h.bankInfo = #{bankInfo} 
    <if test=" prepend="AND" bankAccount> h.bankAccount = #{bankAccount} 
    <if test=" prepend="AND" officeCode> h.officeCode = #{officeCode} 
    <if test=" prepend="AND" profitDepCode> h.profitDepCode = #{profitDepCode} 
    <if test=" prepend="AND" subcontractNo> h.subcontractNo = #{subcontractNo} 
    <if test=" prepend="AND" isAccrued> h.isAccrued = #{isAccrued} 
    <if test=" prepend="AND" isInvoiced> isInvoiced = #{isInvoiced} 
    <if test=" prepend="AND" subcontractAmount> subcontractAmount = #{subcontractAmount} 
    <if test=" prepend="AND" reason> h.reason = #{reason} 
    <if test=" prepend="AND" remark> h.remark = #{remark} 
    <if test=" prepend="AND" effectiveFrom> h.effectiveFrom >= #{effectiveFrom} 
    <if test=" prepend="AND" effectiveTo>  #{effectiveTo} <= IFNULL(h.effectiveTo, "9999-12-31")  
    <if test=" prepend="AND" zrApproveTime> h.zrApproveTime = #{zrApproveTime} 
    <if test=" prepend="AND" createBy> h.createBy = #{createBy} 
    <if test=" prepend="AND" createTime> h.createTime = #{createTime} 
    <if test=" prepend="AND" updateBy> h.updateBy = #{updateBy} 
    <if test=" prepend="AND" updateTime> h.updateTime = #{updateTime} 
    <if test=" prepend="AND" orgId> h.orgId = #{orgId} 

    <if test=" prepend="AND" areaPower> (FIND_IN_SET(h.officeCode, #{areaPower}) or FIND_IN_SET(h.profitDepCode, #{areaPower}))
    <if test=" prepend="AND" projectId> FIND_IN_SET(#{projectId}, h.projectIds) 

    <if test=" prepend="AND" property="customInfo.purchId"> #customInfo.purchId# = h.`customInfo` ->> '$$.purchId' 




    <if test=" searchTimeType compareValue="createTime">
        <if test=" prepend="AND" searchStartTime> h.createTime >= #{searchStartTime} 
        <if test=" prepend="AND" searchEndTime>  h.createTime <= #{searchEndTime}  

    <if test=" searchTimeType compareValue="zrApproverTime">
        <if test=" prepend="AND" searchStartTime> zra.zrApproverTime >= #{searchStartTime} 
        <if test=" prepend="AND" searchEndTime>  zra.zrApproverTime <= #{searchEndTime}  

    <if test=" searchTimeType compareValue="zrApproveTime">
        <if test=" prepend="AND" searchStartTime> h.zrApproveTime >= #{searchStartTime} 
        <if test=" prepend="AND" searchEndTime>  h.zrApproveTime <= #{searchEndTime}  

    <if test=" searchTimeType compareValue="paymentTime">
        <if test=" prepend="AND" searchStartTime> p.paymentTime >= #{searchStartTime} 
        <if test=" prepend="AND" searchEndTime>  p.paymentTime <= #{searchEndTime}  
        GROUP BY h.id

 order by h.id desc

