SELECT DISTINCT h.id AS subcontractId, h.contractNos, h.subcontractNo, h.subcontractName, h.officeCode, dep.departmentName AS officeName, h.profitDepCode, dep2.departmentName AS profitDepName, D.KEY_ AS processKey, D.NAME_ AS processName, RES.ID_ AS taskId, RES.NAME_ AS taskName, CASE WHEN RES.ASSIGNEE_ = 'emlRole' THEN '工程管理部主管' WHEN RES.ASSIGNEE_ = 'emRole' THEN '工程管理部' WHEN RES.ASSIGNEE_ = 'cbRole' THEN '回访人员' WHEN RES.ASSIGNEE_ = 'zrRole' THEN '办事处主任' ELSE IFNULL(fr.roleName, CONCAT(ui.username, '-', ui.realName)) END AS assigneeName, RES.CREATE_TIME_ AS createTime , h.customInfo ->> '$$.purchId' AS purchId , hp.id AS paymentId , hp.ratio AS paymentRatio , hp.amount AS paymentAmount , hp.remark AS paymentRemark , hp.customInfo ->> '$$.status' AS paymentStatus , fc.abbr AS compAbbr FROM ACT_RU_TASK RES INNER JOIN ACT_RU_VARIABLE A0 ON RES.PROC_INST_ID_ = A0.PROC_INST_ID_ INNER JOIN ACT_RE_PROCDEF D ON RES.PROC_DEF_ID_ = D.ID_ INNER JOIN `pm_subcontract_project_header` h ON h.`id` = A0.`LONG_` AND A0.NAME_ = 'subcontractId' AND A0.TASK_ID_ IS NULL AND A0.NAME_ = 'subcontractId' AND A0.TYPE_ = 'integer' AND h.effectiveTo IS NULL LEFT JOIN `pm_subcontract_project_payment` hp ON h.`id` = hp.subcontractId AND D.KEY_ = 'SubcontractInspection' AND hp.confirmTime IS NULL LEFT JOIN fnd_user_info ui ON RES.`ASSIGNEE_` = ui.`username` AND ui.`status` = 1 LEFT JOIN `fnd_roles` fr ON RES.ASSIGNEE_ = CONCAT('role_', fr.id) LEFT JOIN fnd_department dep ON h.`officeCode` = dep.`departmentNum` AND dep.`status` = 1 LEFT JOIN fnd_department dep2 ON h.profitDepCode = dep2.`departmentNum`
AND dep.`status` = 1 LEFT JOIN `fnd_company` fc ON fc.id = h.orgId WHERE RES.SUSPENSION_STATE_ = 1 <if test=" processKey prepend="AND"> D.KEY_ = #{processKey}
<if test=" processKey prepend="AND">
D.KEY_ in ('Subcontract', 'SubcontractCallBack', 'SubcontractInspection')
<if test=" taskId prepend="AND"> RES.ID_ = #{taskId}
<if test=" taskKey prepend="AND"> RES.TASK_DEF_KEY_ = #{taskKey}
AND ( <if test=" assignee prepend=""> (RES.ASSIGNEE_ = #{assignee} OR (RES.ASSIGNEE_ IS NULL AND EXISTS ( SELECT 1 FROM ACT_RU_IDENTITYLINK I LEFT JOIN `act_id_group` g ON g.`ID_` = i.`GROUP_ID_` AND i.`TYPE_` = 'candidate' LEFT JOIN `act_id_membership` im ON im.`GROUP_ID_` = g.`ID_` WHERE I.TASK_ID_ = RES.ID_ AND I.TYPE_ = 'candidate' AND (I.USER_ID_ = #{assignee} OR im.`USER_ID_` = #{assignee}) ) ) )
<if test=" roleGroups>
<if test=" property="roleGroups[].roleGroup" prepend="OR" open="(" close=")"> RES.ASSIGNEE_ = #roleGroups[].roleGroup# <if test=" property="roleGroups[].checkAll" prepend="and"> ( FIND_IN_SET(h.`officeCode`, #{areaPower}) OR FIND_IN_SET(h.`profitDepCode`, #{areaPower}) OR FIND_IN_SET(h.customInfo ->> '$$.parentOfficeCode', #{areaPower}) )
<if test=" property="roleGroups[].checkOffice" prepend="and"> FIND_IN_SET(h.`officeCode`, #{areaPower})
<if test=" property="roleGroups[].checkProfitDep" prepend="and"> FIND_IN_SET(h.`profitDepCode`, #{areaPower})
<if test=" property="roleGroups[].checkParentOffice" prepend="and"> FIND_IN_SET(h.customInfo ->> '$$.parentOfficeCode', #{areaPower})
) <if test=" prepend="AND" subcontractName> h.subcontractName like concat("%", #{subcontractName}, "%") <if test=" prepend="AND" contractNos> (h.contractNos like concat("%", #{contractNos}, "%") or h.subcontractNo like concat("%", #{contractNos}, "%")) <if test=" prepend="AND" facilitatorName> h.facilitatorName like concat("%", #{facilitatorName}, "%") <if test=" prepend="AND" officeCode> h.officeCode = #{officeCode} <if test=" prepend="AND" profitDepCode> h.profitDepCode = #{profitDepCode} <if test=" prepend="AND" subcontractNo> h.subcontractNo = #{subcontractNo} <if test=" prepend="AND" orgId> h.orgId = #{orgId}
<if test=" prepend="AND" purchId> #{purchId} = h.`customInfo` ->> '$$.purchId' ORDER BY RES.CREATE_TIME_ DESC

SELECT DISTINCT h.id AS subcontractId, h.contractNos, h.subcontractNo, h.subcontractName, h.officeCode, dep.departmentName AS officeName, h.profitDepCode, dep2.departmentName AS profitDepName, "Subcontract" AS processKey, "项目转包流程" AS processName, -1 AS taskId, "重新发起申请" AS taskName, "服务经理" AS assigneeName, NULL AS createTime FROM `pm_subcontract_project_header` h LEFT JOIN fnd_department dep ON h.`officeCode` = dep.`departmentNum` AND dep.`status` = 1 LEFT JOIN fnd_department dep2 ON h.profitDepCode = dep2.`departmentNum` AND dep2.isParam = 1 AND dep.`status` = 1 WHERE h.`state` < 0 AND FIND_IN_SET(h.`officeCode`, #{areaPower}) AND h.effectiveTo IS NULL
<if test=" prepend="AND" subcontractName> h.subcontractName like concat("%", #{subcontractName}, "%") <if test=" prepend="AND" contractNos> (h.contractNos like concat("%", #{contractNos}, "%") or h.subcontractNo like concat("%", #{contractNos}, "%")) <if test=" prepend="AND" facilitatorName> h.facilitatorName like concat("%", #{facilitatorName}, "%") <if test=" prepend="AND" officeCode> h.officeCode = #{officeCode} <if test=" prepend="AND" profitDepCode> h.profitDepCode = #{profitDepCode} <if test=" prepend="AND" subcontractNo> h.subcontractNo = #{subcontractNo} <if test=" prepend="AND" orgId> h.orgId = #{orgId}
<if test=" prepend="AND" purchId> #{purchId} = h.`customInfo` ->> '$$.purchId'

select 
    h.`contractNos`, h.`subcontractNo`, h.`subcontractName`, bd.`basicDataName` AS typeName, h.`facilitatorName`, h.`subcontractAmount`, 
    office.`departmentName` AS officeName, profitDep.`departmentName` AS profitDepName, h.reason,
    h.`createTime`, CONCAT(h.createBy, "-", ui.`realName`) AS createName, h.customInfo
    <if test=" prepend="," searchTimeType compareValue="zrApproverTime"> zrTask.zrApproverTime 
    <if test=" prepend="," searchTimeType compareValue="zrApproverTime"> h.zrApproveTime as zrApproverTime,
    bd1.`basicDataName` AS stateName, bd2.`basicDataName` AS callbackStateName, h.`isAccrued`, h.`isInvoiced`, pp.confirmTime, 
    CONCAT(
        ROUND(
            pp.paidAmount / CONVERT(
                REPLACE(h.subcontractAmount, ',', ''), DECIMAL (25, 2)
            ) * 100, 2
        ), "%"
    ) AS paidRatio, pp.paidAmount, pp.paymentTime, pp.remark, pp.customInfo AS extInfo
    , h.orgId
from
    `pm_subcontract_project_header` h
<if test=" searchTimeType compareValue="zrApproverTime">
    left join 
        (select 
            objId as subcontractId, max(assigneeTime) as zrApproverTime 
        from
            `fnd_act_hi_comment` 
        where result = 1 
            and taskKey = 'approveZRTask' 
            and procdefKey = 'Subcontract' 
        group by procdefKey, objId) zrTask 
        on zrTask.subcontractId = h.`id` 

    left join 
        (select 
            t.`subcontractId`, t.confirmTime, t.paymentTime, t.remark, maxPay.paidAmount, t.customInfo
        from
            `pm_subcontract_project_payment` t 
            inner join 
                (select 

                    max(id) AS maxPayId,
                    sum(
                        if(
                            paymentTime is not null, convert(
                                replace(IFNULL(customInfo ->> '$$.paidAmount', amount), ",", ""), DECIMAL (25, 2)
                            ), 0
                        )
                    ) as paidAmount 
                from
                    `pm_subcontract_project_payment` 

                group by subcontractId) maxPay 
                on t.id = maxPay.maxPayId) pp 
        on pp.subcontractId = h.id
<if test=" searchTimeType compareValue="paymentTime">
    LEFT JOIN `pm_subcontract_project_payment` p 
        ON h.id = p.`subcontractId` 

    left join `fnd_basic_data` bd 
        on bd.`basicDataId` = h.`type` 
        and bd.`dataTypeCode` = 'SubcontractType' 
    LEFT JOIN `fnd_basic_data` bd1 
        ON h.`state` = bd1.`basicDataId` 
        AND bd1.`dataTypeCode` = 'subcontractState' 
    LEFT JOIN `fnd_basic_data` bd2 
        ON h.`callbackState` = bd2.`basicDataId` 
        AND bd2.`dataTypeCode` = 'subcontractCbState' 
    left join fnd_department office 
        on office.`departmentNum` = h.`officeCode` 
        and office.`status` = 1 
    left join fnd_department profitDep 
        on profitDep.`departmentNum` = h.`profitDepCode` 
        and profitDep.`status` = 1
    LEFT JOIN fnd_user_info ui 
        ON ui.`username` = h.`createBy`
where h.effectiveTo is NULL
    <if test=" prepend="AND" id> h.id = #{id} 
    <if test=" prepend="AND" subcontractName> h.subcontractName like concat("%", #{subcontractName}, "%") 
    <if test=" prepend="AND" contractNos> (h.contractNos like concat("%", #{contractNos}, "%") or h.subcontractNo like concat("%", #{contractNos}, "%")) 
    <if test=" prepend="AND" projectIds> h.projectIds like concat("%", #{projectIds}, "%")  
    <if test=" prepend="AND" type> h.type = #{type} 
    <if test=" prepend="AND" state> h.state = #{state} 
    <if test=" prepend="AND" callbackState> callbackState = #{callbackState}  
    <if test=" prepend="AND" facilitatorId> h.facilitatorId = #{facilitatorId} 
    <if test=" prepend="AND" facilitatorName> h.facilitatorName like concat("%", #{facilitatorName}, "%") 
    <if test=" prepend="AND" bankInfo> h.bankInfo = #{bankInfo} 
    <if test=" prepend="AND" bankAccount> h.bankAccount = #{bankAccount} 
    <if test=" prepend="AND" officeCode> h.officeCode = #{officeCode} 
    <if test=" prepend="AND" profitDepCode> h.profitDepCode = #{profitDepCode} 
    <if test=" prepend="AND" subcontractNo> h.subcontractNo = #{subcontractNo} 
    <if test=" prepend="AND" isAccrued> h.isAccrued = #{isAccrued} 
    <if test=" prepend="AND" isInvoiced> isInvoiced = #{isInvoiced} 
    <if test=" prepend="AND" subcontractAmount> subcontractAmount = #{subcontractAmount} 
    <if test=" prepend="AND" reason> h.reason = #{reason} 
    <if test=" prepend="AND" remark> h.remark = #{remark} 
    <if test=" prepend="AND" effectiveFrom> h.effectiveFrom >= #{effectiveFrom} 
    <if test=" prepend="AND" effectiveTo>  #{effectiveTo} <= IFNULL(h.effectiveTo, "9999-12-31")  
    <if test=" prepend="AND" zrApproveTime> h.zrApproveTime = #{zrApproveTime} 
    <if test=" prepend="AND" createBy> h.createBy = #{createBy} 
    <if test=" prepend="AND" createTime> h.createTime = #{createTime} 
    <if test=" prepend="AND" updateBy> h.updateBy = #{updateBy} 
    <if test=" prepend="AND" updateTime> h.updateTime = #{updateTime} 
    <if test=" prepend="AND" orgId> h.orgId = #{orgId} 
    <if test=" prepend="AND" areaPower> (FIND_IN_SET(h.officeCode, #{areaPower}) or FIND_IN_SET(h.profitDepCode, #{areaPower}))
    <if test=" prepend="AND" projectId> FIND_IN_SET(#{projectId}, h.projectIds) 
    <if test=" prepend="AND" property="customInfo.purchId"> #customInfo.purchId# = h.`customInfo` ->> '$$.purchId' 
    <if test=" searchTimeType compareValue="createTime">
        <if test=" prepend="AND" searchStartTime> h.createTime >= #{searchStartTime} 
        <if test=" prepend="AND" searchEndTime>  h.createTime <= #{searchEndTime}  

    <if test=" searchTimeType compareValue="zrApproverTime">
        <if test=" prepend="AND" searchStartTime> zrTask.zrApproverTime >= #{searchStartTime} 
        <if test=" prepend="AND" searchEndTime>  zrTask.zrApproverTime <= #{searchEndTime}  

    <if test=" searchTimeType compareValue="zrApproveTime">
        <if test=" prepend="AND" searchStartTime> h.zrApproveTime >= #{searchStartTime} 
        <if test=" prepend="AND" searchEndTime>  h.zrApproveTime <= #{searchEndTime}  

    <if test=" searchTimeType compareValue="paymentTime">
        <if test=" prepend="AND" searchStartTime> p.paymentTime >= #{searchStartTime} 
        <if test=" prepend="AND" searchEndTime>  p.paymentTime <= #{searchEndTime}  
        GROUP BY h.id

 order by h.id desc

