) OR (
sseId NOT IN (SELECT id FROM `pm_subcontract_project_payment_sse`) AND 'SSE' = IFNULL(customInfo ->> '$$.relateSource', 'SSE') AND sseId > 0 ) ) AND FIND_IN_SET(subcontractId, #{subcontractIds})
